    public static UBSVendBankAccountAccountIdOrigField find(RecId _recId)
    {
        UBSVendBankAccountAccountIdOrigField vendBankAccountAccountIdOrigField;

        select firstonly vendBankAccountAccountIdOrigField where vendBankAccountAccountIdOrigField.RecId  ==_recId;

        return vendBankAccountAccountIdOrigField;
    }

    public static UBSVendBankAccountAccountIdOrigField findVendAccountTableAccountId(VendBankAccountId _accountId)
    {
        UBSVendBankAccountAccountIdOrigField vendBankAccountAccountIdOrigField;

        select firstonly vendBankAccountAccountIdOrigField 
            where vendBankAccountAccountIdOrigField.AccountID == _accountId;

        return vendBankAccountAccountIdOrigField;
    }
